// src/modules/projects/routes.js
const express = require('express');
const router = express.Router();
const projectsService = require('../projects/service');
const { sendError } = require('../../lib/errors');
const { randomUUID } = require('node:crypto');

router.get('/', (req, res) => {
  const projects = projectsService.getAllProjects();
  res.json({ projects });
});

router.get('/:projectId', (req, res) => {
  const projectId = req.params.projectId;
  const project = projectsService.getProjectById(projectId);

  if (!project) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }

  res.json({ project });
});

router.post('/', (req, res) => {
  const { name } = req.body;

  if (!name || typeof name !== 'string' || name.trim() === '') {
    return sendError(res, 400, 'INVALID_PROJECT_NAME', 'Invalid project name');
  }

  const projectId = randomUUID();
  const project = projectsService.createProject(projectId, { name });
  res.status(201).json({ project });
});

module.exports = router;

