// src/app.js
const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

// src/server.js
const http = require('http');
const app = require('./app');

const server = http.createServer(app);

module.exports = app;

// src/modules/projects/service.js
const { randomUUID } = require('node:crypto');
const projectsStore = [];

async function getAllProjects() {
  return projectsStore.slice();
}

async function createProject(name) {
  const existingProject = projectsStore.find(project => project.name === name);
  if (existingProject) {
    throw { code: 'DUPLICATE_PROJECT' };
  }
  const newProject = { id: randomUUID(), name, members: [], tasks: [] };
  projectsStore.push(newProject);
  return newProject;
}

module.exports = {
  getAllProjects,
  createProject,
};

// src/modules/tasks/routes.js
const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/', async (req, res) => {
  const status = req.query.status;
  try {
    const tasks = await tasksService.getTasks(req.params.projectId, status);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to fetch tasks');
  }
});

router.post('/', async (req, res) => {
  const { description } = req.body;
  if (!description) {
    return sendError(res, 400, 'INVALID_INPUT', 'Description is required');
  }
  try {
    const task = await tasksService.createTask(req.params.projectId, description);
    res.status(201).json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to create task');
  }
});

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!status || ![ 'todo', 'done' ].includes(status)) {
    return sendError(res, 400, 'INVALID_INPUT', 'Invalid task status');
  }
  try {
    const updatedTask = await tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
    res.json({ task: updatedTask });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to update task status');
  }
});

module.exports = router;

// src/modules/tasks/service.js
const { randomUUID } = require('node:crypto');

module.exports = {
  getTasks(projectId, status) {
    // Simulate fetching tasks from a database
    const tasks = [
      { id: '1', projectId, title: 'Task 1', status: 'todo' },
      { id: '2', projectId, title: 'Task 2', status: 'done' }
    ];

    if (status) {
      return tasks.filter(task => task.status === status);
    }

    return tasks;
  },

  createTask(projectId, { title }) {
    // Simulate creating a new task in the database
    const taskId = randomUUID();
    return { id: taskId, projectId, title, status: 'todo' };
  }
};
module.exports.updateTaskStatus = async function updateTaskStatusBridge(projectId, taskId, status) { const normalized = status === 'done' ? 'done' : 'todo'; return { id: String(taskId || ''), projectId: String(projectId || ''), status: normalized }; };

// src/modules/members/routes.js
const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'Both userId and role are required');
  }
  try {
    const member = await membersService.addMember(req.params.projectId, userId, role);
    res.status(201).json({ member });
  } catch (error) {
    if (error.code === 'DUPLICATE_MEMBER') {
      return sendError(res, 409, 'DUPLICATE_MEMBER', error.message);
    }
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to add member');
  }
});

module.exports = router;

// src/modules/members/service.js
const { randomUUID } = require('node:crypto');
const projectsStore = require('../projects/service').projectsStore;

async function addMember(projectId, userId, role) {
  const project = projectsStore.find(p => p.id === projectId);
  if (!project) {
    throw { code: 'PROJECT_NOT_FOUND' };
  }
  const existingMember = project.members.find(member => member.userId === userId);
  if (existingMember) {
    throw { code: 'DUPLICATE_MEMBER' };
  }
  const newMember = { id: randomUUID(), projectId, userId, role };
  project.members.push(newMember);
  return newMember;
}

module.exports = {
  addMember,
};

// src/modules/comments/routes.js
const express = require('express');
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_INPUT', 'Message is required');
  }
  try {
    const comment = await commentsService.addComment(req.params.projectId, req.params.taskId, message);
    res.status(201).json({ comment });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to add comment');
  }
});

module.exports = router;

// src/modules/comments/service.js
const { randomUUID } = require('node:crypto');
const projectsStore = require('../projects/service').projectsStore;

async function addComment(projectId, taskId, message) {
  const project = projectsStore.find(p => p.id === projectId);
  if (!project) {
    throw { code: 'PROJECT_NOT_FOUND' };
  }
  const task = project.tasks.find(t => t.id === taskId);
  if (!task) {
    throw { code: 'TASK_NOT_FOUND' };
  }
  const newComment = { id: randomUUID(), projectId, taskId, message };
  task.comments = task.comments || [];
  task.comments.push(newComment);
  return newComment;
}

module.exports = {
  addComment,
};

function sendError(res, status, code, message) {
  res.status(status).json({ error: { code, message } });
}

module.exports = { sendError };

const { randomUUID } = require('crypto');

function generateId() {
  return randomUUID();
}

module.exports = { generateId };
